export const loadTestTask = 'task-0' as const;
export const loadTestTaskLabel = 'Task 0' as const;
export const loadTestScenario = 'task-0-canonical' as const;
export const loadTestScenarioLabel = 'Task 0 canonical load test scenario' as const;
export const loadTestProfile = 'baseline' as const;
export const loadTestProfileLabel = 'baseline' as const;
export const loadTestEnvironment = 'local' as const;
export const loadTestEnvironmentLabel = 'local' as const;
export const loadTestWorkflow = 'baseline-supporting-reads-documents-workspace-fleetgraph-chat' as const;
export const loadTestWorkflowLabel = 'Task 0 baseline workflow mix' as const;

import {
  loadTestConfig,
  loadTestEnvironmentLabel,
  loadTestProfileLabel,
  loadTestScenarioLabel,
  loadTestTargetDefaults,
  loadTestTaskLabel,
  loadTestWorkflowLabel,
} from '../loadtest.config.js';

import autocannon from 'autocannon';
import {
  loadTestConfig,
  loadTestEnvironmentLabel,
  loadTestProfileLabel,
  loadTestScenarioLabel,
  loadTestTargetDefaults,
  loadTestTaskLabel,
  loadTestWorkflowLabel,
} from '../loadtest.config.js';

type FlowType =
  | 'supporting-read'
  | 'document-load'
  | 'workspace-load'
  | 'fleetgraph-thread-create'
  | 'fleetgraph-thread-reuse'
  | 'fleetgraph-chat-followup';

type SupportedMethod = 'GET' | 'POST';

interface ScenarioStep {
  method: SupportedMethod;
  path: string;
  flow: FlowType;
  body?: () => unknown;
  tags?: Record<string, string>;
}

const sessionCookie = loadTestTargetDefaults.sessionCookie;
const workspaceId = loadTestTargetDefaults.workspaceId;
const documentId = loadTestTargetDefaults.documentId;
const searchQueries = loadTestTargetDefaults.searchQueries;
const chatQuestions = loadTestTargetDefaults.chatQuestions;
const activeSearchQuery = searchQueries[0] ?? 'workspace';
const initialThreadId = process.env.LOADTEST_THREAD_ID?.trim() || undefined;

let chatThreadId = initialThreadId;
let chatTurn = 0;
let fleetGraphThreadCreates = 0;
let fleetGraphThreadReuses = 0;

const createChatBody = (question: string) => ({
  entityType: 'workspace',
  entityId: workspaceId,
  question,
  ...(chatThreadId ? { threadId: chatThreadId } : {}),
});

const task0Steps: ScenarioStep[] = [
  { method: 'GET', path: `/api/search/mentions?q=${encodeURIComponent(activeSearchQuery)}`, flow: 'supporting-read', tags: { task: loadTestConfig.task, taskLabel: loadTestTaskLabel } },
  { method: 'GET', path: `/api/documents/${documentId}`, flow: 'document-load' },
  { method: 'GET', path: `/api/workspaces/${workspaceId}`, flow: 'workspace-load' },
  {
    method: 'POST',
    path: '/api/fleetgraph/chat/thread',
    flow: 'fleetgraph-thread-create',
    body: () => ({ entityType: 'workspace', entityId: workspaceId }),
  },
  {
    method: 'POST',
    path: '/api/fleetgraph/chat/thread',
    flow: 'fleetgraph-thread-reuse',
    body: () => ({ entityType: 'workspace', entityId: workspaceId, ...(chatThreadId ? { threadId: chatThreadId } : {}) }),
  },
  {
    method: 'POST',
    path: '/api/fleetgraph/chat',
    flow: 'fleetgraph-chat-followup',
    body: () => createChatBody(chatQuestions[0] ?? 'What changed this week?'),
  },
  {
    method: 'POST',
    path: '/api/fleetgraph/chat',
    flow: 'fleetgraph-chat-followup',
    body: () => createChatBody(chatQuestions[1] ?? 'Summarize the current workspace.'),
  },
  {
    method: 'POST',
    path: '/api/fleetgraph/chat',
    flow: 'fleetgraph-chat-followup',
    body: () => createChatBody(chatQuestions[2] ?? 'What should we follow up on next?'),
  },
];

const loadTestFlowGroup = loadTestConfig.scenario;

const scenario = {
  duration: loadTestConfig.duration,
  connections: loadTestConfig.connections,
  steps: task0Steps,
};

const requestPlan = scenario.steps.map((step) => ({
  method: step.method,
  path: step.path,
  body: step.body,
  flow: step.flow,
  tags: {
    ...step.tags,
    scenario: loadTestConfig.scenario,
    profile: loadTestConfig.profile,
    environment: loadTestConfig.environment,
    flowGroup: loadTestFlowGroup,
  },
}));

const headers = {
  cookie: sessionCookie,
  'content-type': 'application/json',
  'x-loadtest-scenario': loadTestConfig.scenario,
  'x-loadtest-profile': loadTestConfig.profile,
  'x-loadtest-environment': loadTestConfig.environment,
  'x-loadtest-workspace-id': workspaceId,
};

const instance = autocannon({
  url: loadTestConfig.baseUrl,
  connections: scenario.connections,
  duration: scenario.duration,
  amount: loadTestConfig.requests > 0 ? loadTestConfig.requests : undefined,
  headers,
  requests: requestPlan.map((step, index) => ({
    method: step.method,
    path: step.path,
    body: typeof step.body === 'function' ? JSON.stringify(step.body()) : undefined,
    onResponse: (statusCode: number, resBody: Buffer) => {
      if (step.path === '/api/fleetgraph/chat/thread' && statusCode >= 200 && statusCode < 300) {
        try {
          const parsed = JSON.parse(resBody.toString('utf8')) as { thread?: { id?: string }; id?: string };
          const nextThreadId = parsed.thread?.id ?? parsed.id;
          if (nextThreadId && nextThreadId !== chatThreadId) {
            fleetGraphThreadCreates += chatThreadId ? 0 : 1;
            fleetGraphThreadReuses += chatThreadId ? 1 : 0;
          }
          chatThreadId = nextThreadId ?? chatThreadId;
        } catch {
          // ignore malformed responses in metrics collection
        }
      }
      if (step.path === '/api/fleetgraph/chat' && statusCode >= 200 && statusCode < 300) {
        chatTurn += 1;
      }
      return index;
    },
  })),
} as Parameters<typeof autocannon>[0]);

autocannon.track(instance, { renderProgressBar: true });

instance.on('done', (result) => {
  console.log(
    JSON.stringify(
      {
        task: loadTestConfig.task,
        taskLabel: loadTestTaskLabel,
        scenario: loadTestConfig.scenario,
        scenarioLabel: loadTestScenarioLabel,
        profile: loadTestConfig.profile,
        profileLabel: loadTestProfileLabel,
        environment: loadTestConfig.environment,
        environmentLabel: loadTestEnvironmentLabel,
        workflow: loadTestConfig.workflow,
        workflowLabel: loadTestWorkflowLabel,
        baseUrl: loadTestConfig.baseUrl,
        workspaceId,
        documentId,
        duration: scenario.duration,
        connections: scenario.connections,
        requestCount: requestPlan.length,
        flows: scenario.steps.map((step, index) => ({ index, flow: step.flow, method: step.method, path: step.path, task: loadTestConfig.task, taskLabel: loadTestTaskLabel })),
        requestPlan: requestPlan.map((step) => ({ method: step.method, path: step.path, flow: step.flow, tags: step.tags })),
        metricsTags: {
          task: loadTestConfig.task,
          taskLabel: loadTestTaskLabel,
          scenario: loadTestConfig.scenario,
          profile: loadTestConfig.profile,
          environment: loadTestConfig.environment,
          workspaceId,
          requestCount: requestPlan.length,
          flowGroup: loadTestFlowGroup,
        },
        chatThreadId,
        chatTurn,
        requestsPerSecond: result.requests.average,
        requestTotals: result.requests,
        latency: result.latency,
        throughput: result.throughput,
        non2xx: result.non2xx,
        errors: result.errors,
        timeouts: result.timeouts,
        statusCodeStats: result.statusCodeStats,
        errorCodes: result.errorCodes,
        latencyDistribution: result.latencyDistribution,
      },
      null,
      2,
    ),
  );
});
